/* tape_block_setters.c: setter functions for libspectrum_tape_block
   Generated to match the getter pattern in tape_accessors.c.
   These functions were declared in libspectrum.h but not present in
   the distributed source (normally generated by a build system).
*/

#include "config.h"
#include "internals.h"
#include "tape_block.h"

#define SET_OK  return LIBSPECTRUM_ERROR_NONE
#define SET_ERR \
  libspectrum_print_error( \
    LIBSPECTRUM_ERROR_INVALID, \
    "invalid block type 0x%02x given to %s", block->type, __func__ \
  ); \
  return LIBSPECTRUM_ERROR_INVALID

/* ── bit0_length ────────────────────────────────────────────────────────── */
libspectrum_error
libspectrum_tape_block_set_bit0_length( libspectrum_tape_block *block, libspectrum_dword v )
{
  switch( block->type ) {
    case LIBSPECTRUM_TAPE_BLOCK_PURE_DATA: block->types.pure_data.bit0_length = v; SET_OK;
    case LIBSPECTRUM_TAPE_BLOCK_TURBO:     block->types.turbo.bit0_length     = v; SET_OK;
    default: SET_ERR;
  }
}

